# write_users.ps1 — writes the updated Users.tsx (with permanent-delete) to disk.
# Run from D:\INDUVISTA\frontend.  Base64 avoids quoting/CRLF issues.
$ErrorActionPreference = "Stop"
$target = "src/pages/Users.tsx"
$b64 = @"

"@
$bytes = [System.Convert]::FromBase64String($b64.Trim())
$text  = [System.Text.Encoding]::UTF8.GetString($bytes)
if (Test-Path $target) { Copy-Item $target "$target.bak_delete" -Force }
[System.IO.File]::WriteAllText((Resolve-Path -LiteralPath ".").Path + "\src\pages\Users.tsx", $text)
Write-Host "Wrote updated Users.tsx (backup: Users.tsx.bak_delete)" -ForegroundColor Green
